void make_small_sqares(unsigned int inv) {
    unsigned int c, addr, y, l, m1, m2;
    unsigned short data, pattern1, pattern2;

    for (c=0;c<32;c++) { 
        addr = c*32;
        printf("# Addr=%04X, 0x%02X (%d)\n", addr, c, c);
        m1 = 1;
        m2 = 2;
        for (y=0;y<3;y++) {
            pattern1 = (c & m1) ? 0xFF00 : 0;
            pattern2 = (c & m2) ? 0x00FF : 0;
            data = pattern1 | pattern2;
            for (l=0;l<8;l++) {
                printf("%04X\n", data ^ inv);
            }
            m1 <<=2;
            m2 <<=2;
        }        
    }
}



void make_16x24_v2(void) {

    unsigned int c, l, i, cel, addr;
    unsigned int data;

    printf("#File_format=Hex\n");
    printf("#Address_depth=6144\n");
    printf("#Data_width=16\n");

    // 32 first characters (custom)
    make_small_sqares(0xFFFF);

    // 95 ASCII characters (standard)
    for (c=0;c<95;c++) {
        i = c + 32;
        addr = i*24;
        printf("# Addr=%04X, 0x%02X (%d)\n", addr, i, i);
        for (l=0;l<24;l++) {
            cel = 0 + (c * 24 + l) * 2;
            data = Arial_round_16x24[cel+0]<<8;
            data |= Arial_round_16x24[cel+1];
            printf("%04X\n", data);
        }
    }

    // 1 last character (custom)
    printf("# Addr=%04X, 0x%02X (%d)\n", addr, i, i);
    for (l=0;l<24;l++) {
        data = (l%2) ? 0x5555 : 0xAAAA;
        printf("%04X\n", data);
    }
}



int main(void) {

    make_16x24_v2();

    return 0;
}